import { recipes } from "./recipes";
import type { Recipe } from "../types/recipe.types";
import type { Page } from "../types/page.types";

const BASE_URL = "https://delishlyrecipes.com";
// header
const header = (
  title: string,
  description: string,
  url: string,
  pageType: "normal" | "list" | "recipe" = "normal",
  itemList?: Recipe[],
  image: string = `${BASE_URL}/icon.jpg`,
  recipe?: Recipe,
) => {
  const ogType = pageType === "recipe" ? "article" : "website";

  let jsonLD: any = {};

  if (pageType === "recipe" && recipe) {
    jsonLD = {
      "@context": "https://schema.org",
      "@type": "Recipe",
      name: recipe.title,
      description: recipe.description,
      image: `${BASE_URL}${recipe.image}`,
      author: { "@type": "Organization", name: "Delishly Recipes" },
      publisher: {
        "@type": "Organization",
        name: "Delishly Recipes",
        logo: { "@type": "ImageObject", url: `${BASE_URL}/icon.jpg` },
      },
      recipeIngredient: recipe.sections.ingerdiants.map(
        (i) => `${i.quantity} ${i.ingredient}`,
      ),
      recipeInstructions: recipe.sections.instructions.paragraph
        .split("\n")
        .map((step) => step.trim())
        .filter((s) => s)
        .map((step) => ({ "@type": "HowToStep", text: step })),
      prepTime: `PT${recipe.sections.details.prep}M`,
      cookTime: `PT${recipe.sections.details.cook}M`,
      totalTime: `PT${
        recipe.sections.details.prep + recipe.sections.details.cook
      }M`,
      recipeYield: `${recipe.sections.details.servings} servings`,
      keywords: recipe.tags || [],
    };
  } else if (pageType === "list" && itemList) {
    jsonLD = {
      "@context": "https://schema.org",
      "@type": "ItemList",
      name: title,
      description,
      url: `${BASE_URL}${url}`,
      itemListElement: itemList.map((item, index) => ({
        "@type": "ListItem",
        position: index + 1,
        url: `${BASE_URL}${item.url}`,
      })),
    };
  } else {
    jsonLD = {
      "@context": "https://schema.org",
      "@type": "WebPage",
      name: title,
      description,
      url: `${BASE_URL}${url}`,
      author: { "@type": "Organization", name: "Delishly Recipes" },
      publisher: {
        "@type": "Organization",
        name: "Delishly Recipes",
        logo: { "@type": "ImageObject", url: `${BASE_URL}/icon.jpg` },
      },
    };
  }

  return `
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <meta name="description" content="${description}">
    <title>${title}</title>
    <link rel="icon" href="/icon.jpg" type="image/x-icon">
    <link rel="canonical" href="${BASE_URL}${url}" />
    <meta property="og:title" content="${title}" />
    <meta property="og:description" content="${description}" />
    <meta property="og:type" content="${ogType}" />
    <meta property="og:url" content="${BASE_URL}${url}" />
    <meta property="og:image" content="${image}" />
    <meta name="twitter:card" content="summary_large_image" />
    <meta name="twitter:title" content="${title}" />
    <meta name="twitter:description" content="${description}" />
    <meta name="twitter:image" content="${image}" />
    <script type="application/ld+json">
    ${JSON.stringify(jsonLD, null, 2)}
    </script>
  `;
};
// body
const body = (main: string, includeHeader: boolean = true) => {
  const header = `<link rel="preload" as="image" href="/icon.jpg"/><header><div><a href="/"><img src="/icon.jpg" alt="Delishly Recipes" title="Delishly Recipes" width="48" height="48"/><span>Delishly Recipes</span></a><nav aria-label="Main Navigation"><a href="/">Home</a><a href="/recipes/">All Recipes</a><a href="/about/">About</a><a href="/contact/">Contact</a></nav><div><a href="/recipes/"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m21 21-4.34-4.34"></path><circle cx="11" cy="11" r="8"></circle></svg>Search Recipes</a><button aria-label="Toggle menu"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M4 5h16"></path><path d="M4 12h16"></path><path d="M4 19h16"></path></svg></button></div></div></header>`;
  const footer = `<link rel="preload" as="image" href="/icon.jpg"/><footer aria-label="Footer Section"><div><section aria-labelledby="footer-brand"><h2 id="footer-brand">Delishly Recipes</h2><a href="/"><img src="/icon.jpg" alt="Delishly Recipes" title="Delishly Recipes" width="48" height="48"/><span>Delishly Recipes</span></a><p>Delishly Recipes shares easy, tested, and delicious recipes for breakfast, lunch, dinner, and quick 30-minute meals.</p></section><div><section aria-labelledby="footer-explore"><h4 id="footer-explore">Explore</h4><ul><li><a href="/recipes/">Recipes</a></li><li><a href="/recipes/">Categories</a></li><li><a href="/recipes/">30-Minute Meals</a></li><li><a href="/recipes/">Trending</a></li></ul></section><section aria-labelledby="footer-company"><h4 id="footer-company">Company</h4><ul><li><a href="/about/">About</a></li><li><a href="/contact/">Contact</a></li><li><a href="/">Privacy Policy</a></li><li><a href="/">Terms of Service</a></li></ul></section><section aria-labelledby="footer-stay-connected"><h4 id="footer-stay-connected">Stay Connected</h4><p>Follow us for daily recipe inspiration.</p><div><a href="https://www.instagram.com/delishlyrecipes/" target="_blank" rel="noopener">Instagram</a><a href="https://www.pinterest.com/delishlyrecipes/" target="_blank" rel="noopener">Pinterest</a><a href="https://github.com/lamgaldam-tech/delishlyrecipes" target="_blank" rel="noopener">GitHub</a></div></section></div><div>© <!-- -->2026<!-- --> Delishly Recipes. All rights reserved.</div></div></footer>`;
  return `${includeHeader ? header + "\n" : ""}${main}\n${footer}`;
};
const recipesBodies = [
  '<link rel="preload" as="image" href="/images/creamy-tuscan-garlic-chicken.jpg"/><header><img src="/images/creamy-tuscan-garlic-chicken.jpg" alt="Creamy Tuscan Garlic Chicken"/><div></div><div><div><a href="/"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m12 19-7-7 7-7"></path><path d="M19 12H5"></path></svg> All Recipes</a><span><span>🍝</span><span>Dinner</span></span><h1>Creamy Tuscan Garlic Chicken</h1></div></div></header><main><div><div><section><p><a href="https://www.google.com/search?q=sun-dried+tomatoes">Sun-dried tomatoes</a>, garlic, and spinach in a <a href="https://www.google.com/search?q=creamy+parmesan+sauce">creamy parmesan sauce</a> over tender chicken breasts.</p></section><section aria-label="Recipe Quick Stats"><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Prep</p><time dateTime="PT10M">10<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Cook</p><time dateTime="PT25M">25<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"></path><path d="M16 3.128a4 4 0 0 1 0 7.744"></path><path d="M22 21v-2a4 4 0 0 0-3-3.87"></path><circle cx="9" cy="7" r="4"></circle></svg><p>Servings</p><p>4</p></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3q1 4 4 6.5t3 5.5a1 1 0 0 1-14 0 5 5 0 0 1 1-3 1 1 0 0 0 5 0c0-2-1.5-3-1.5-5q0-2 2.5-4"></path></svg><p>Calories</p><p>420</p></div></section><section aria-labelledby="overview-header"><h2 id="overview-header">About Creamy Tuscan Garlic Chicken</h2><p>Creamy Tuscan Garlic Chicken is a beloved dinner recipe that combines the robust flavors of Italy with a comforting creamy sauce. Tender chicken breasts are lightly seasoned and seared to a golden perfection. Heavy cream provides a luscious base, balanced by sharp parmesan cheese, creating a rich mouthfeel. <a href="https://www.google.com/search?q=sun-dried+tomatoes">Sun-dried tomatoes</a> introduce a subtle tang, complementing the garlic&#x27;s aromatic punch, while fresh spinach adds vibrancy and a hint of earthiness. This dish is visually stunning and full of flavor. It’s suitable for weekday meals or special dinners and pairs beautifully with pasta or crusty bread to soak up the sauce. The cooking process is simple but rewards careful attention, ensuring the chicken remains moist while the sauce is creamy and smooth. Variations with mushrooms, herbs, or different cheeses allow for personalization. Leftovers store well in the fridge and the sauce can be reheated gently. Overall, this recipe exemplifies Italian comfort food, combining practicality with indulgence, making it a go-to for home cooks seeking flavor, texture, and presentation in one dish.</p></section><section aria-labelledby="instructions-header"><h2 id="instructions-header">How to Make</h2><p>Season chicken with salt, pepper, and <a href="https://www.google.com/search?q=italian+seasoning">Italian seasoning</a>. Heat olive oil in a skillet over medium-high heat and sear chicken 5-6 minutes per side until golden, then set aside. Sauté minced garlic for 30 seconds until fragrant. Add <a href="https://www.google.com/search?q=sun-dried+tomatoes">sun-dried tomatoes</a> and cook 2 minutes. Pour in heavy cream and stir in parmesan until melted. Add spinach and cook until wilted. Return chicken to skillet, spoon sauce over top, and simmer 5 minutes. Serve hot over pasta or with bread. Adjust seasoning to taste. Take care not to overcook chicken to retain moisture. Deglaze the pan with wine for added depth if desired. Cooking this dish develops layers of flavor, with each ingredient contributing texture and aroma. The sauce should be smooth and creamy, clinging to the chicken. Serve immediately to enjoy optimal taste, texture, and presentation. Garnish with fresh herbs for a final touch. This method ensures balanced flavors, combining richness, tang, and aromatics harmoniously.</p></section><section aria-labelledby="tips-header"><h2 id="tips-header">Pro Tips</h2><p>Use room temperature chicken for even cooking. Avoid overcooking to maintain juiciness. Sauté garlic just until fragrant to prevent bitterness. Deglaze pan with white wine for flavor depth. Add spinach at the end to maintain color and texture. Thin sauce with chicken stock if too thick. Customize with herbs like thyme or rosemary. Serve immediately; leftovers reheat gently. Heavy-bottom skillet helps distribute heat evenly. Ensure chicken is not overcrowded to allow searing. Adjust seasoning to taste before serving. This dish scales well, but cook in batches if needed. Use fresh ingredients for optimal flavor. Presentation is key: drizzle sauce over chicken and garnish with herbs or parmesan. Pair with sides to complete the meal. Enjoy the rich, creamy sauce and tender chicken in every bite. These tips guarantee consistent, delicious results.</p></section><section aria-labelledby="faq-header"><h2 id="faq-header">FAQ</h2><p>Q: Can I use chicken thighs? A: Yes, cook slightly longer. Q: Can I prep ahead? A: Make sauce in advance and reheat. Q: Dairy-free option? A: Use coconut cream and nutritional yeast. Q: Recommended sides? A: Pasta, roasted veggies, or bread. Q: How long in fridge? A: Up to 2 days. Q: Freezing? A: Freeze sauce separately up to 1 month. Q: Can I add mushrooms? A: Yes, sauté and add with tomatoes. Q: Can I adjust spices? A: Yes, customize herbs and seasoning to taste. Q: Suitable for kids? A: Mildly spiced versions work well. Q: Can sauce be thicker? A: Reduce over low heat to desired consistency. Q: How to reheat leftovers? A: Warm gently on stove or microwave. Q: Pairing wine? A: White wines like Chardonnay complement flavors. Q: Can I double the recipe? A: Yes, cook in batches to avoid overcrowding.</p></section><section aria-labelledby="more-like-header"><h2 id="more-like-header">More Like Creamy Tuscan Garlic Chicken</h2></section></div><aside><section aria-labelledby="ingredients-header"><header><h2 id="ingredients-header">Ingredients</h2><div><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path></svg></button><span>1<!-- -->x</span><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path><path d="M12 5v14"></path></svg></button></div></header><ul><li><span></span><span><strong>4 pieces</strong> <!-- -->Chicken breasts</span></li><li><span></span><span><strong>1/2 cup</strong> <!-- -->Sun-dried tomatoes</span></li><li><span></span><span><strong>2 cups</strong> <!-- -->Fresh spinach</span></li><li><span></span><span><strong>1 cup</strong> <!-- -->Heavy cream</span></li><li><span></span><span><strong>1/2 cup</strong> <!-- -->Parmesan cheese</span></li><li><span></span><span><strong>4 minced</strong> <!-- -->Garlic cloves</span></li><li><span></span><span><strong>2 tbsp</strong> <!-- -->Olive oil</span></li><li><span></span><span><strong>1 tsp</strong> <!-- -->Italian seasoning</span></li></ul><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"></path><path d="M6 9V3a1 1 0 0 1 1-1h10a1 1 0 0 1 1 1v6"></path><rect x="6" y="14" width="12" height="8" rx="1"></rect></svg>Print Recipe</button></section><section aria-labelledby="tags-header"><h3 id="tags-header">Tags</h3><div><span>#<!-- -->chicken</span><span>#<!-- -->italian</span><span>#<!-- -->creamy</span><span>#<!-- -->quick</span></div></section></aside></div></main>',
  '<link rel="preload" as="image" href="/images/fluffy-japanese-souffle-pancakes.jpg"/><header><img src="/images/fluffy-japanese-souffle-pancakes.jpg" alt="Fluffy Japanese Soufflé Pancakes"/><div></div><div><div><a href="/"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m12 19-7-7 7-7"></path><path d="M19 12H5"></path></svg> All Recipes</a><span><span>🥞</span><span>Breakfast</span></span><h1>Fluffy Japanese Soufflé Pancakes</h1></div></div></header><main><div><div><section><p>Impossibly fluffy and jiggly pancakes that melt in your mouth, topped with fresh berries and maple syrup.</p></section><section aria-label="Recipe Quick Stats"><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Prep</p><time dateTime="PT15M">15<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Cook</p><time dateTime="PT15M">15<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"></path><path d="M16 3.128a4 4 0 0 1 0 7.744"></path><path d="M22 21v-2a4 4 0 0 0-3-3.87"></path><circle cx="9" cy="7" r="4"></circle></svg><p>Servings</p><p>2</p></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3q1 4 4 6.5t3 5.5a1 1 0 0 1-14 0 5 5 0 0 1 1-3 1 1 0 0 0 5 0c0-2-1.5-3-1.5-5q0-2 2.5-4"></path></svg><p>Calories</p><p>280</p></div></section><section aria-labelledby="overview-header"><h2 id="overview-header">About Fluffy Japanese Soufflé Pancakes</h2><p>Fluffy Japanese Soufflé Pancakes are a delicate, airy breakfast treat known for their jiggly texture and pillowy softness. This recipe involves separating eggs, whisking yolks with milk and vanilla, and folding in sifted flour. Egg whites are whipped to stiff peaks with sugar, then folded gently into the batter, preserving airiness. Slow cooking over low heat with optional <a href="https://www.google.com/search?q=ring+molds+pancakes">ring molds</a> ensures even rise and a soft interior. Each bite melts in your mouth with subtle sweetness. Serve with berries, maple syrup, or powdered sugar for visual appeal and flavor balance. Patience and precision in folding and cooking are essential to achieving the signature texture. Variations include matcha, chocolate, or fruit-infused flavors, providing creative flexibility. Ideal for brunch, special occasions, or weekend breakfasts, these pancakes are visually impressive and deliver a delicate, café-quality experience at home. Mastering them enhances baking confidence and showcases attention to culinary detail. The combination of careful technique, gentle folding, and low heat produces the iconic soufflé pancakes that have captured the hearts of dessert and breakfast lovers worldwide. Understanding ingredient ratios, whipping methods, and cooking time ensures consistency, repeatability, and impressive results. Enjoying these pancakes is a balance of aesthetics, taste, and texture, elevating a simple breakfast into a memorable meal.</p></section><section aria-labelledby="instructions-header"><h2 id="instructions-header">How to Make</h2><p><a href="https://www.google.com/search?q=whisk+egg+yolks">Whisk egg yolks</a>, milk, and vanilla until smooth. Sift in cake flour and baking powder, folding gently. Beat egg whites with cream of tartar until foamy, gradually adding sugar to stiff peaks. Fold one-third meringue into yolk mixture, then the rest, preserving volume. Heat a non-stick pan on low heat, place <a href="https://www.google.com/search?q=ring+molds+pancakes">ring molds</a>, fill halfway with batter. Cover and cook 6-7 minutes until bottom is golden. Flip carefully, cook another 5-6 minutes covered. Remove molds, serve with berries, syrup, or toppings. Maintain low heat to ensure interior is fluffy and set. Gentle folding preserves air pockets, critical for texture. Patience and precise technique are essential. With practice, these pancakes rise evenly and maintain jiggly, soft structure. Use spatulas and <a href="https://www.google.com/search?q=ring+molds+pancakes">ring molds</a> for uniformity. This approach guarantees the classic soufflé pancake appearance, taste, and texture reminiscent of Japanese cafés, offering a light, airy breakfast delight suitable for family, friends, or special occasions.</p></section><section aria-labelledby="tips-header"><h2 id="tips-header">Pro Tips</h2><p>Separate eggs at room temperature to achieve maximum volume. Beat whites to stiff peaks but avoid overbeating. Fold gently to maintain airiness. Use <a href="https://www.google.com/search?q=ring+molds+pancakes">ring molds</a> for uniform height. Cook on lowest heat to prevent browning. Fresh berries or syrup enhance taste and presentation. Variations with matcha, cocoa, or fruit are encouraged. Cover pan tightly to trap steam and promote rise. Silicone spatula is ideal for folding without deflating. Cook in small batches if doubling recipe. Ensure patience; rushing compromises fluffiness. Adjust sugar slightly for taste. Enjoy immediately for optimal texture. Leftovers lose signature jiggly texture, so best served fresh. Pair with a hot beverage or light syrup. Mastery comes with repeated attempts, observing folding technique and cooking time for consistent results.</p></section><section aria-labelledby="faq-header"><h2 id="faq-header">FAQ</h2><p>Q: Can I make without <a href="https://www.google.com/search?q=ring+molds+pancakes">ring molds</a>? A: Yes, shape may vary. Q: How to store leftovers? A: Refrigerate for a few hours, reheat gently. Q: Can I freeze? A: Not recommended; texture suffers. Q: Flavor variations? A: Vanilla, matcha, or chocolate work. Q: Cooking duration? A: Low heat until set. Q: Double recipe? A: Yes, cook in batches. Q: Can I use milk alternatives? A: Yes, but flavor may change. Q: Can I use all-purpose flour? A: Cake flour preferred for light texture. Q: Should I beat yolks first? A: Yes, ensures smooth batter. Q: Why fold gently? A: Preserves airiness. Q: Can I add fruit inside? A: Small pieces work, adjust cooking. Q: Pan temperature? A: Lowest possible for slow cooking. Q: Best serving? A: Immediately for best texture.</p></section><section aria-labelledby="more-like-header"><h2 id="more-like-header">More Like Fluffy Japanese Soufflé Pancakes</h2><a href="/recipes/garlic-butter-chicken-thigh/s">Garlic Butter Chicken Thighs</a><a href="/recipes/one-pan-creamy-mushroom-chicke/n">One-Pan Creamy Mushroom Chicken</a><a href="/recipes/parmesan-crusted-chicke/n">Parmesan Crusted Chicken</a></section></div><aside><section aria-labelledby="ingredients-header"><header><h2 id="ingredients-header">Ingredients</h2><div><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path></svg></button><span>1<!-- -->x</span><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path><path d="M12 5v14"></path></svg></button></div></header><ul><li><span></span><span><strong>2 </strong> <!-- -->Egg yolks</span></li><li><span></span><span><strong>3 </strong> <!-- -->Egg whites</span></li><li><span></span><span><strong>1/4 cup</strong> <!-- -->Cake flour</span></li><li><span></span><span><strong>2 tbsp</strong> <!-- -->Sugar</span></li><li><span></span><span><strong>2 tbsp</strong> <!-- -->Milk</span></li><li><span></span><span><strong>1 tsp</strong> <!-- -->Vanilla extract</span></li><li><span></span><span><strong>1/2 tsp</strong> <!-- -->Baking powder</span></li><li><span></span><span><strong>1/4 tsp</strong> <!-- -->Cream of tartar</span></li></ul><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"></path><path d="M6 9V3a1 1 0 0 1 1-1h10a1 1 0 0 1 1 1v6"></path><rect x="6" y="14" width="12" height="8" rx="1"></rect></svg>Print Recipe</button></section><section aria-labelledby="tags-header"><h3 id="tags-header">Tags</h3><div><span>#<!-- -->pancakes</span><span>#<!-- -->japanese</span><span>#<!-- -->breakfast</span><span>#<!-- -->fluffy</span></div></section></aside></div></main>',
  '<link rel="preload" as="image" href="/images/mediterranean-quinoa-power-bowl.jpg"/><header><img src="/images/mediterranean-quinoa-power-bowl.jpg" alt="Mediterranean Quinoa Power Bowl"/><div></div><div><div><a href="/"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m12 19-7-7 7-7"></path><path d="M19 12H5"></path></svg> All Recipes</a><span><span>🥗</span><span>Lunch</span></span><h1>Mediterranean Quinoa Power Bowl</h1></div></div></header><main><div><div><section><p>A vibrant and nutritious bowl packed with quinoa, roasted veggies, feta, and a lemon-tahini dressing.</p></section><section aria-label="Recipe Quick Stats"><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Prep</p><time dateTime="PT15M">15<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Cook</p><time dateTime="PT20M">20<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"></path><path d="M16 3.128a4 4 0 0 1 0 7.744"></path><path d="M22 21v-2a4 4 0 0 0-3-3.87"></path><circle cx="9" cy="7" r="4"></circle></svg><p>Servings</p><p>3</p></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3q1 4 4 6.5t3 5.5a1 1 0 0 1-14 0 5 5 0 0 1 1-3 1 1 0 0 0 5 0c0-2-1.5-3-1.5-5q0-2 2.5-4"></path></svg><p>Calories</p><p>380</p></div></section><section aria-labelledby="overview-header"><h2 id="overview-header">About Mediterranean Quinoa Power Bowl</h2><p>The Mediterranean Quinoa Power Bowl is a colorful, nutritious, and satisfying lunch option, combining the wholesomeness of quinoa with the freshness of Mediterranean vegetables and the tanginess of feta cheese. Each bowl is a harmonious combination of textures and flavors: tender, nutty quinoa serves as the base, while roasted chickpeas provide crispness and a protein boost. Cherry tomatoes and cucumbers contribute juiciness and crunch, and kalamata olives add a savory depth. Tahini-lemon dressing binds everything together with its nutty, creamy flavor. This recipe emphasizes the balance between nutrient density and taste, ensuring that each bite is satisfying and wholesome. It’s perfect for meal prep, as it stores well and retains flavors over time. The vibrant colors make it visually appealing, and the variety of textures keeps every bite interesting. Preparation is straightforward, making it accessible for anyone looking to enjoy a health-conscious meal without compromising on flavor. This bowl exemplifies the principles of Mediterranean cuisine, focusing on fresh, wholesome ingredients, simple cooking techniques, and bold flavor combinations. The dish is naturally vegetarian and can be made vegan by ensuring tahini dressing contains no honey or other animal products. It’s ideal for anyone seeking a nutritious, balanced, and visually appealing lunch option that is high in protein, fiber, and healthy fats while remaining light and refreshing.</p></section><section aria-labelledby="instructions-header"><h2 id="instructions-header">How to Make</h2><p>Cook quinoa according to package instructions and allow it to cool slightly. Roast chickpeas tossed with olive oil and cumin at 400°F for 20 minutes until crispy. Chop cherry tomatoes and cucumber into bite-sized pieces. Prepare the dressing by whisking together tahini, lemon juice, garlic, and water until smooth. Assemble the bowl: start with quinoa as the base, add roasted chickpeas, tomatoes, cucumber, olives, and crumbled feta on top. Drizzle generously with tahini-lemon dressing. Garnish with fresh herbs like parsley or cilantro and a squeeze of lemon. Serve immediately or refrigerate for later consumption. This step-by-step process ensures even distribution of flavors and textures. The roasted chickpeas provide crunch contrasting the tender quinoa. The dressing complements the natural sweetness of vegetables, tying the bowl together harmoniously. Variations include adding roasted red peppers, artichokes, or avocado for additional nutrients and flavor complexity. This method produces a healthy, satisfying, and visually appealing meal, perfect for lunch or light dinner.</p></section><section aria-labelledby="tips-header"><h2 id="tips-header">Pro Tips</h2><p>Cook quinoa with a pinch of salt for better flavor. Roast chickpeas evenly, tossing halfway through for uniform crispiness. Use ripe tomatoes and fresh cucumber for optimal taste. Prepare dressing ahead to let flavors meld. Garnish with herbs to enhance freshness. Adjust dressing thickness with water if needed. Mix ingredients gently to prevent quinoa from becoming mushy. Store components separately for meal prep to maintain textures. Use high-quality tahini for nutty depth. Consider adding spices like smoked paprika or sumac for variation. This bowl is highly customizable; substitute vegetables according to season or preference. Include a protein like grilled chicken or tofu if desired. Maintain color contrast to enhance visual appeal. Serve chilled or at room temperature for best flavor. These tips ensure a flavorful, nutritious, and satisfying meal every time.</p></section><section aria-labelledby="faq-header"><h2 id="faq-header">FAQ</h2><p>Q: Can I use brown rice instead of quinoa? A: Yes, adjust cooking time. Q: Can it be made vegan? A: Yes, ensure tahini contains no animal products. Q: How long does it keep? A: 2-3 days in fridge. Q: Can I prep in advance? A: Yes, store components separately. Q: Can I add protein? A: Tofu or grilled chicken work. Q: Can I freeze? A: Not recommended; vegetables lose texture. Q: Dressing variations? A: Add garlic, herbs, or lemon zest. Q: Can I add seeds? A: Yes, pumpkin or sunflower seeds add crunch. Q: Best serving temp? A: Chilled or room temperature. Q: Suitable for kids? A: Mild flavors preferred. Q: Can I make it spicy? A: Add chili flakes or hot sauce.</p></section><section aria-labelledby="more-like-header"><h2 id="more-like-header">More Like Mediterranean Quinoa Power Bowl</h2><a href="/recipes/matcha-souffle-pancake/s">Matcha Soufflé Pancakes</a><a href="/recipes/japanese-cheesecake-pancake/s">Japanese Cheesecake Pancakes</a><a href="/recipes/fluffy-lemon-pancake/s">Fluffy Lemon Pancakes</a></section></div><aside><section aria-labelledby="ingredients-header"><header><h2 id="ingredients-header">Ingredients</h2><div><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path></svg></button><span>1<!-- -->x</span><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path><path d="M12 5v14"></path></svg></button></div></header><ul><li><span></span><span><strong>1 cup</strong> <!-- -->Quinoa</span></li><li><span></span><span><strong>1 cup</strong> <!-- -->Cherry tomatoes</span></li><li><span></span><span><strong>1 diced</strong> <!-- -->Cucumber</span></li><li><span></span><span><strong>1/3 cup</strong> <!-- -->Kalamata olives</span></li><li><span></span><span><strong>1/2 cup</strong> <!-- -->Feta cheese</span></li><li><span></span><span><strong>1 can</strong> <!-- -->Chickpeas</span></li><li><span></span><span><strong>3 tbsp</strong> <!-- -->Tahini</span></li><li><span></span><span><strong>2 tbsp</strong> <!-- -->Lemon juice</span></li></ul><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"></path><path d="M6 9V3a1 1 0 0 1 1-1h10a1 1 0 0 1 1 1v6"></path><rect x="6" y="14" width="12" height="8" rx="1"></rect></svg>Print Recipe</button></section><section aria-labelledby="tags-header"><h3 id="tags-header">Tags</h3><div><span>#<!-- -->healthy</span><span>#<!-- -->vegan-option</span><span>#<!-- -->mediterranean</span><span>#<!-- -->bowl</span></div></section></aside></div></main>',
  '<link rel="preload" as="image" href="/images/classic-tiramisu.jpg"/><header><img src="/images/classic-tiramisu.jpg" alt="Classic Tiramisu"/><div></div><div><div><a href="/"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m12 19-7-7 7-7"></path><path d="M19 12H5"></path></svg> All Recipes</a><span><span>🍰</span><span>Desserts</span></span><h1>Classic Tiramisu</h1></div></div></header><main><div><div><section><p>Layers of espresso-soaked ladyfingers and mascarpone cream dusted with rich cocoa powder.</p></section><section aria-label="Recipe Quick Stats"><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Prep</p><time dateTime="PT30M">30<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Cook</p><time dateTime="PT0M">0<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"></path><path d="M16 3.128a4 4 0 0 1 0 7.744"></path><path d="M22 21v-2a4 4 0 0 0-3-3.87"></path><circle cx="9" cy="7" r="4"></circle></svg><p>Servings</p><p>8</p></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3q1 4 4 6.5t3 5.5a1 1 0 0 1-14 0 5 5 0 0 1 1-3 1 1 0 0 0 5 0c0-2-1.5-3-1.5-5q0-2 2.5-4"></path></svg><p>Calories</p><p>350</p></div></section><section aria-labelledby="overview-header"><h2 id="overview-header">About Classic Tiramisu</h2><p>Classic Tiramisu is an iconic Italian dessert celebrated for its luxurious layering of espresso-soaked ladyfingers and smooth mascarpone cream, dusted with rich cocoa powder. Each bite delivers a perfect balance of sweetness, coffee bitterness, and creamy texture. Traditionally served chilled, it is elegant enough for special occasions yet simple enough for home preparation. The espresso-soaked ladyfingers form a delicate sponge that soaks up flavor without becoming soggy, while mascarpone cream provides a velvety richness. Sugar and egg yolks combine to create a smooth custard, complemented by whipped cream for lightness. Optionally, a splash of Kahlúa or coffee liqueur adds complexity. Preparing Tiramisu requires layering ingredients carefully, ensuring even distribution and avoiding mixing layers. The dessert benefits from refrigeration for several hours or overnight to meld flavors fully. Its versatility allows for variations such as chocolate shavings, flavored liqueurs, or fruit infusions. Tiramisu exemplifies Italian culinary art, balancing flavor, texture, and presentation. This dessert not only satisfies a sweet craving but also demonstrates technique, patience, and attention to detail, offering a decadent and memorable dining experience.</p></section><section aria-labelledby="instructions-header"><h2 id="instructions-header">How to Make</h2><p>Brew espresso and allow to cool. Mix in Kahlúa if desired. Beat egg yolks with sugar until thick and pale. Incorporate mascarpone cheese until smooth. Whip heavy cream to soft peaks and fold into mascarpone mixture. Quickly dip ladyfingers into espresso, arranging them in a single layer in a dish. Spread half of mascarpone cream over ladyfingers. Repeat layers, finishing with cream on top. Dust generously with cocoa powder. Cover and refrigerate at least 6 hours, preferably overnight. Ensure layers remain intact while assembling to maintain structure. The slow chilling allows flavors to meld, producing a creamy, coffee-infused dessert. Presentation is important; dust cocoa evenly and serve chilled. This method ensures a balanced dessert with rich, creamy texture and the classic flavor profile that defines traditional Tiramisu. Slicing carefully maintains layers and offers a visually appealing serving. Leftovers can be stored covered in the refrigerator, retaining taste and texture for up to 2 days.</p></section><section aria-labelledby="tips-header"><h2 id="tips-header">Pro Tips</h2><p>Use freshly brewed espresso for best flavor. Do not over-soak ladyfingers to prevent sogginess. Use high-quality mascarpone for creamy texture. Whip egg whites or cream to soft peaks for lightness. Chill for at least 6 hours or overnight for optimal flavor. Dust cocoa just before serving for presentation. Optional liqueur enhances aroma and depth. Assemble in a shallow dish for easier slicing. Ensure even layers for balanced taste. Use a fine-mesh sieve to dust cocoa powder uniformly. Tiramisu can be customized with chocolate shavings or berries. Maintain hygiene when handling raw eggs; consider pasteurized eggs if concerned. Serve chilled; do not freeze. This approach ensures consistent flavor, texture, and appearance, making it a memorable dessert that delights guests and family alike.</p></section><section aria-labelledby="faq-header"><h2 id="faq-header">FAQ</h2><p>Q: Can I make Tiramisu ahead? A: Yes, refrigerate overnight. Q: Can I use sponge cake instead? A: Ladyfingers are traditional, but sponge works. Q: Alcohol-free version? A: Omit Kahlúa or coffee liqueur. Q: How long does it keep? A: Up to 2 days in fridge. Q: Can I freeze? A: Not recommended; texture changes. Q: How to serve? A: Slice carefully to maintain layers. Q: Can I use decaf coffee? A: Yes, flavor slightly changes. Q: Can I make individual portions? A: Yes, use small cups or jars. Q: Can I add chocolate? A: Shavings or cocoa powder work. Q: Can I use whipped cream only? A: Mascarpone provides traditional flavor. Q: How to prevent sogginess? A: Do not over-soak ladyfingers.</p></section><section aria-labelledby="more-like-header"><h2 id="more-like-header">More Like Classic Tiramisu</h2><a href="/recipes/greek-quinoa-sala/d">Greek Quinoa Salad</a><a href="/recipes/roasted-veggie-buddha-bow/l">Roasted Veggie Buddha Bowl</a><a href="/recipes/mediterranean-chickpea-bow/l">Mediterranean Chickpea Bowl</a></section></div><aside><section aria-labelledby="ingredients-header"><header><h2 id="ingredients-header">Ingredients</h2><div><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path></svg></button><span>1<!-- -->x</span><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path><path d="M12 5v14"></path></svg></button></div></header><ul><li><span></span><span><strong>500g</strong> <!-- -->Mascarpone cheese</span></li><li><span></span><span><strong>24 pieces</strong> <!-- -->Ladyfinger biscuits</span></li><li><span></span><span><strong>1.5 cups</strong> <!-- -->Espresso</span></li><li><span></span><span><strong>4 </strong> <!-- -->Egg yolks</span></li><li><span></span><span><strong>1/2 cup</strong> <!-- -->Sugar</span></li><li><span></span><span><strong>1 cup</strong> <!-- -->Heavy cream</span></li><li><span></span><span><strong>for dusting</strong> <!-- -->Cocoa powder</span></li><li><span></span><span><strong>2 tbsp</strong> <!-- -->Kahlúa (optional)</span></li></ul><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"></path><path d="M6 9V3a1 1 0 0 1 1-1h10a1 1 0 0 1 1 1v6"></path><rect x="6" y="14" width="12" height="8" rx="1"></rect></svg>Print Recipe</button></section><section aria-labelledby="tags-header"><h3 id="tags-header">Tags</h3><div><span>#<!-- -->italian</span><span>#<!-- -->dessert</span><span>#<!-- -->no-bake</span><span>#<!-- -->classic</span></div></section></aside></div></main>',
  '<link rel="preload" as="image" href="/images/spicy-thai-basil-stir-fry.jpg"/><header><img src="/images/spicy-thai-basil-stir-fry.jpg" alt="Spicy Thai Basil Stir-Fry"/><div></div><div><div><a href="/"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m12 19-7-7 7-7"></path><path d="M19 12H5"></path></svg> All Recipes</a><span><span>🍝</span><span>Dinner</span></span><h1>Spicy Thai Basil Stir-Fry</h1></div></div></header><main><div><div><section><p>A fiery and aromatic stir-fry with ground pork, Thai basil, and chilies served over jasmine rice.</p></section><section aria-label="Recipe Quick Stats"><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Prep</p><time dateTime="PT10M">10<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Cook</p><time dateTime="PT10M">10<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"></path><path d="M16 3.128a4 4 0 0 1 0 7.744"></path><path d="M22 21v-2a4 4 0 0 0-3-3.87"></path><circle cx="9" cy="7" r="4"></circle></svg><p>Servings</p><p>2</p></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3q1 4 4 6.5t3 5.5a1 1 0 0 1-14 0 5 5 0 0 1 1-3 1 1 0 0 0 5 0c0-2-1.5-3-1.5-5q0-2 2.5-4"></path></svg><p>Calories</p><p>450</p></div></section><section aria-labelledby="overview-header"><h2 id="overview-header">About Spicy Thai Basil Stir-Fry</h2><p>Spicy Thai Basil Stir-Fry, known as Pad Krapow in Thailand, is a fast and aromatic dish that delivers bold flavors with minimal cooking time. Ground pork is stir-fried with fresh Thai basil leaves, garlic, and fiery chilies, resulting in a pungent and spicy dish that excites the senses. Soy sauce, oyster sauce, and fish sauce create a balanced umami base, harmonizing with the heat from chilies and the herbal aroma of basil. Served over fragrant jasmine rice, this dish is both filling and flavorful. Its quick cooking method preserves texture and freshness while ensuring the intense flavors remain vibrant. Thai Basil Stir-Fry exemplifies the balance of heat, aroma, and umami that defines authentic Thai cuisine. This dish is highly adaptable, allowing substitution of proteins such as chicken, beef, or tofu. The combination of spices, fresh herbs, and sauces produces a layered flavor profile that is simultaneously savory, spicy, and aromatic. Perfect for weeknight dinners, it requires only a few ingredients yet delivers restaurant-quality taste at home. The dish is celebrated for its simplicity, speed, and authentic flavor, making it a staple in Thai home cooking and an accessible introduction to bold Asian flavors.</p></section><section aria-labelledby="instructions-header"><h2 id="instructions-header">How to Make</h2><p>Cook jasmine rice according to package directions. Heat oil in a wok over high heat until smoking. Add minced garlic and sliced chilies, stir-frying for 30 seconds to release aroma. Add ground pork, breaking it apart, cooking 3-4 minutes until browned. Stir in soy sauce, oyster sauce, fish sauce, and a pinch of sugar. Toss in Thai basil leaves, stir until wilted. Serve immediately over hot jasmine rice, optionally topping with a fried egg. Maintain high heat to achieve quick cooking and preserve aromatic flavors. Constant stirring ensures even cooking and prevents burning. Adjust chilies to desired spice level. Garnish with additional basil for freshness. The method ensures balanced texture: tender meat, slightly wilted herbs, and aromatic sauce coating each grain of rice. Variations can include vegetables like bell peppers, snap peas, or carrots to increase color and nutritional value. This recipe is ideal for quick, satisfying, and flavor-packed dinners.</p></section><section aria-labelledby="tips-header"><h2 id="tips-header">Pro Tips</h2><p>Use fresh Thai basil for authentic aroma. Adjust chilies for heat preference. Maintain high heat for proper stir-fry technique. Mince garlic finely for even distribution. Stir constantly to prevent burning. Serve immediately for best texture. Optional: add bell peppers or snap peas. Cook rice separately to prevent soggy texture. Use a wok if possible; pan works too. Measure sauces before cooking to streamline process. Customize spice level to taste. Garnish with extra basil leaves for aroma and presentation. Add a fried egg on top to enrich flavor and texture. This dish benefits from quick cooking, ensuring flavors are concentrated and fresh.</p></section><section aria-labelledby="faq-header"><h2 id="faq-header">FAQ</h2><p>Q: Can I use chicken instead of pork? A: Yes, adjust cooking time. Q: Can I make it less spicy? A: Reduce chilies. Q: Can it be vegetarian? A: Use tofu and vegetarian sauces. Q: Can I prep in advance? A: Cook fresh for best flavor. Q: Can I add vegetables? A: Yes, bell peppers, snap peas, carrots work. Q: How long can leftovers be stored? A: Up to 2 days in fridge. Q: Can I freeze? A: Not recommended; basil loses flavor. Q: What side dish works? A: Jasmine rice is traditional. Q: Can I adjust sauce? A: Yes, taste and balance umami. Q: Can I add fried egg? A: Yes, enhances flavor and texture. Q: Best cooking method? A: High-heat stir-fry ensures authentic flavor.</p></section><section aria-labelledby="more-like-header"><h2 id="more-like-header">More Like Spicy Thai Basil Stir-Fry</h2><a href="/recipes/no-bake-chocolate-tiramis/u">No-Bake Chocolate Tiramisu</a><a href="/recipes/strawberry-tiramisu-cup/s">Strawberry Tiramisu Cups</a><a href="/recipes/coffee-panna-cott/a">Coffee Panna Cotta</a></section></div><aside><section aria-labelledby="ingredients-header"><header><h2 id="ingredients-header">Ingredients</h2><div><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path></svg></button><span>1<!-- -->x</span><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path><path d="M12 5v14"></path></svg></button></div></header><ul><li><span></span><span><strong>400g</strong> <!-- -->Ground pork</span></li><li><span></span><span><strong>2 cups</strong> <!-- -->Thai basil leaves</span></li><li><span></span><span><strong>3-5 sliced</strong> <!-- -->Thai chilies</span></li><li><span></span><span><strong>5 minced</strong> <!-- -->Garlic cloves</span></li><li><span></span><span><strong>2 tbsp</strong> <!-- -->Soy sauce</span></li><li><span></span><span><strong>1 tbsp</strong> <!-- -->Oyster sauce</span></li><li><span></span><span><strong>1 tbsp</strong> <!-- -->Fish sauce</span></li><li><span></span><span><strong>for serving</strong> <!-- -->Jasmine rice</span></li></ul><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"></path><path d="M6 9V3a1 1 0 0 1 1-1h10a1 1 0 0 1 1 1v6"></path><rect x="6" y="14" width="12" height="8" rx="1"></rect></svg>Print Recipe</button></section><section aria-labelledby="tags-header"><h3 id="tags-header">Tags</h3><div><span>#<!-- -->thai</span><span>#<!-- -->spicy</span><span>#<!-- -->quick</span><span>#<!-- -->stir-fry</span></div></section></aside></div></main>',
  '<link rel="preload" as="image" href="/images/lemon-garlic-butter-shrimp.jpeg"/><header><img src="/images/lemon-garlic-butter-shrimp.jpeg" alt="Lemon Garlic Butter Shrimp"/><div></div><div><div><a href="/"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="m12 19-7-7 7-7"></path><path d="M19 12H5"></path></svg> All Recipes</a><span><span>🍝</span><span>Dinner</span></span><h1>Lemon Garlic Butter Shrimp</h1></div></div></header><main><div><div><section><p>Juicy <a href="google.com">shrimp</a> cooked in a zesty <a href="google.com">lemon</a> garlic <a href="google.com">butter</a> sauce, served over rice or pasta.</p></section><section aria-label="Recipe Quick Stats"><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Prep</p><time dateTime="PT10M">10<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><circle cx="12" cy="12" r="10"></circle><path d="M12 6v6l4 2"></path></svg><p>Cook</p><time dateTime="PT15M">15<!-- --> min</time></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"></path><path d="M16 3.128a4 4 0 0 1 0 7.744"></path><path d="M22 21v-2a4 4 0 0 0-3-3.87"></path><circle cx="9" cy="7" r="4"></circle></svg><p>Servings</p><p>3</p></div><div><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M12 3q1 4 4 6.5t3 5.5a1 1 0 0 1-14 0 5 5 0 0 1 1-3 1 1 0 0 0 5 0c0-2-1.5-3-1.5-5q0-2 2.5-4"></path></svg><p>Calories</p><p>300</p></div></section><section aria-labelledby="overview-header"><h2 id="overview-header">About Lemon Garlic Butter Shrimp</h2><p>Garlic <a href="google.com">Butter</a> <a href="google.com">Shrimp</a> is an incredibly flavorful dish that combines the rich, creamy taste of <a href="google.com">butter</a> with the bright, zesty notes of fresh <a href="google.com">lemon</a>, creating a balance that is both indulgent and refreshing. Each <a href="google.com">shrimp</a> is cooked to perfection, seared just enough to develop a slightly caramelized surface while remaining tender and juicy on the inside. The minced garlic infuses the <a href="google.com">butter</a> with aromatic intensity, creating layers of savory depth that complement the natural sweetness of the <a href="google.com">shrimp</a>.\n\nPaprika adds a subtle smoky undertone, while salt and pepper enhance all the flavors without overpowering them. Fresh parsley sprinkled on top provides a burst of herbal brightness and a touch of color, making the dish visually appealing as well as delicious. This recipe is ideal for quick weeknight dinners, elegant date-night meals, or even as a versatile appetizer for parties.\n\nIt pairs beautifully with a side of fluffy rice, buttery pasta, or even a crisp green salad. The cooking process is simple yet rewarding, requiring only a few minutes to achieve restaurant-quality results in your own kitchen. The combination of ingredients works harmoniously to produce a dish that is both comforting and impressive. The buttery sauce clings to the <a href="google.com">shrimp</a>, ensuring every bite is rich and satisfying.\n\n<a href="google.com">Lemon</a> juice added at the end brightens the overall <a href="google.com">flavor</a> profile, cutting through the richness of the <a href="google.com">butter</a> and creating a more balanced taste. The recipe is forgiving and adaptable; spices can be adjusted according to preference, and additional aromatics such as chili flakes or white wine can be incorporated to elevate the complexity. Leftovers, if any, can be gently reheated without losing texture or <a href="google.com">flavor</a>, making it a practical choice for busy lifestyles.\n\nGarlic <a href="google.com">Butter</a> <a href="google.com">Shrimp</a> exemplifies how simple ingredients can combine to produce a sophisticated and deeply enjoyable dish that appeals to all ages and occasions. Its rich flavors, simple preparation, and visually appealing presentation make it a favorite in home kitchens and perfect for sharing with friends or family.</p></section><section aria-labelledby="instructions-header"><h2 id="instructions-header">How to Make</h2><p>To prepare Garlic <a href="google.com">Butter</a> <a href="google.com">Shrimp</a>, begin by melting <a href="google.com">butter</a> and adding olive oil to a skillet over medium heat, allowing the mixture to warm evenly. Once the fat is heated, add the minced garlic and sauté for just a few seconds until fragrant, being careful not to let it brown or burn, as this can create bitterness.\n\nNext, add the <a href="google.com">shrimp</a>, ensuring they are spread in a single layer in the pan, so each piece sears properly and cooks evenly. Season the <a href="google.com">shrimp</a> with paprika, salt, and pepper, making sure every piece is coated with the spices. As the <a href="google.com">shrimp</a> <a href="google.com">cook</a>, they will turn a bright pink color and curl slightly, signaling that they are nearing doneness. Cooking time is short—usually just a few minutes per side—so constant attention is important to avoid overcooking, which can make the <a href="google.com">shrimp</a> rubbery.\n\nAfter the <a href="google.com">shrimp</a> are cooked through, squeeze the juice of a fresh <a href="google.com">lemon</a> over them, allowing the citrus to meld with the garlic <a href="google.com">butter</a> and create a vibrant, tangy <a href="google.com">flavor</a>. Remove the skillet from the heat and sprinkle freshly chopped parsley on top to enhance aroma and presentation. Serve the <a href="google.com">shrimp</a> immediately, either as a standalone appetizer or accompanied by rice, pasta, or vegetables.\n\nThe method ensures that the <a href="google.com">shrimp</a> remain juicy, the garlic <a href="google.com">butter</a> sauce is smooth and flavorful, and the dish is ready to impress with minimal effort. The process is simple but emphasizes precision and timing, ensuring the perfect balance of texture and taste for every bite. This method also allows for small customizations like adding chili flakes, wine, or herbs to further enrich the flavors.</p></section><section aria-labelledby="tips-header"><h2 id="tips-header">Pro Tips</h2><p>When making Garlic <a href="google.com">Butter</a> <a href="google.com">Shrimp</a>, using fresh <a href="google.com">shrimp</a> is essential for the best <a href="google.com">flavor</a> and texture, as frozen <a href="google.com">shrimp</a> can sometimes release excess water, diluting the sauce. Avoid overcrowding the skillet to allow the <a href="google.com">shrimp</a> to sear properly and develop caramelization, which enhances taste. Mince the garlic finely and add it to the pan at the correct time to prevent bitterness while releasing its full aroma.\n\nAdjust the amount of paprika to taste, as it adds a subtle smoky warmth without overpowering the natural <a href="google.com">flavor</a> of the <a href="google.com">shrimp</a>. Adding <a href="google.com">lemon</a> juice at the end balances the richness of the <a href="google.com">butter</a> and lifts the dish, creating a more rounded <a href="google.com">flavor</a> profile. Fresh parsley provides not only color but also a herbaceous note that complements the seafood perfectly. Serve immediately to maintain the juiciness and temperature, as reheating can change the texture slightly, though gentle reheating is possible.\n\nThis dish pairs beautifully with rice, pasta, or bread to soak up the buttery sauce, making it versatile for various meals. Small variations, like incorporating white wine, chili flakes, or garlic powder, can personalize the dish according to preference. These tips ensure consistency, allowing anyone to prepare Garlic <a href="google.com">Butter</a> <a href="google.com">Shrimp</a> that is flavorful, tender, and visually appealing, suitable for casual dinners or special occasions alike. Attention to detail in cooking time, seasoning, and finishing touches ensures every plate is a success.</p></section><section aria-labelledby="faq-header"><h2 id="faq-header">FAQ</h2><p>Q: Can I use frozen <a href="google.com">shrimp</a>? A: Yes, but thaw completely and pat dry to avoid watery sauce. Frozen <a href="google.com">shrimp</a> often release extra liquid that can dilute the garlic <a href="google.com">butter</a>, affecting <a href="google.com">flavor</a> and texture. Proper thawing ensures even cooking and that the <a href="google.com">shrimp</a> sear nicely rather than steam. Rinsing and drying them also helps the <a href="google.com">butter</a> and seasonings cling better.\n\nQ: Can I make this dairy-free? A: Substitute <a href="google.com">butter</a> with olive oil or vegan <a href="google.com">butter</a>. The <a href="google.com">flavor</a> profile will shift slightly, but using olive oil keeps the richness while allowing the garlic and spices to shine. Adjust seasoning as needed, and finish with <a href="google.com">lemon</a> juice to brighten the dish, maintaining balance in the absence of dairy.\n\nQ: How to prevent overcooking? A: <a href="google.com">Shrimp</a> <a href="google.com">cook</a> very quickly, usually 2-3 minutes per side. Overcooked <a href="google.com">shrimp</a> become rubbery and lose their sweet, tender texture. Watch for the color change to opaque pink and the curling shape. Remove immediately from heat once done. Residual heat can finish cooking slightly without overcooking.\n\nQ: Can I prep ahead? A: You can prepare the garlic <a href="google.com">butter</a> sauce and chop ingredients in advance, but <a href="google.com">cook</a> the <a href="google.com">shrimp</a> just before serving. Pre-cooking the <a href="google.com">shrimp</a> is possible, but they lose their ideal texture upon reheating. Assemble components so minimal effort is needed at the last moment to ensure freshness and juiciness.\n\nQ: Can I add extra flavors? A: Yes, customize with chili flakes for heat, white wine for depth, or fresh herbs like thyme. The recipe is versatile and forgiving, so small adjustments enhance it without ruining the base flavors. <a href="google.com">Lemon</a> juice should be added at the end to balance richness and retain brightness.\n\nQ: What to serve with it? A: Garlic <a href="google.com">Butter</a> <a href="google.com">Shrimp</a> pairs well with rice, pasta, crusty bread, or a fresh salad. The buttery sauce clings to these accompaniments beautifully, turning even simple sides into a satisfying, cohesive meal. Consider serving alongside roasted vegetables for color and texture variety.\n\nQ: Can it be doubled? A: Absolutely, but <a href="google.com">cook</a> <a href="google.com">shrimp</a> in batches to prevent overcrowding. Overcrowding releases water, preventing proper sear and altering texture. Batch cooking ensures each <a href="google.com">shrimp</a> cooks evenly, maintains <a href="google.com">flavor</a>, and gets coated in garlic <a href="google.com">butter</a> perfectly.\n\nQ: How to store leftovers? A: Store <a href="google.com">shrimp</a> separately from sauce for up to one day in the fridge. Gently reheat to prevent toughness. Leftovers can be added to pastas or salads, but fresh cooking is always best for taste and texture. Avoid freezing if possible, as it changes the delicate texture of cooked <a href="google.com">shrimp</a>.</p></section><section aria-labelledby="more-like-header"><h2 id="more-like-header">More Like Lemon Garlic Butter Shrimp</h2><a href="/recipes/creamy-tuscan-garlic-chicke/n">Creamy Tuscan Garlic Chicken</a><a href="/recipes/spicy-thai-basil-stir-fr/y">Spicy Thai Basil Stir-Fry</a><a href="/recipes/classic-tiramis/u">Classic Tiramisu</a></section></div><aside><section aria-labelledby="ingredients-header"><header><h2 id="ingredients-header">Ingredients</h2><div><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path></svg></button><span>1<!-- -->x</span><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M5 12h14"></path><path d="M12 5v14"></path></svg></button></div></header><ul><li><span></span><span><strong>500g</strong> <!-- -->Shrimp</span></li><li><span></span><span><strong>3 tbsp</strong> <!-- -->Butter</span></li><li><span></span><span><strong>4 cloves</strong> <!-- -->Garlic</span></li><li><span></span><span><strong>1 tbsp</strong> <!-- -->Olive oil</span></li><li><span></span><span><strong>1 </strong> <!-- -->Lemon</span></li><li><span></span><span><strong>1 tsp</strong> <!-- -->Paprika</span></li><li><span></span><span><strong>to taste</strong> <!-- -->Salt and pepper</span></li><li><span></span><span><strong>2 tbsp</strong> <!-- -->Fresh parsley</span></li></ul><button><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" aria-hidden="true"><path d="M6 18H4a2 2 0 0 1-2-2v-5a2 2 0 0 1 2-2h16a2 2 0 0 1 2 2v5a2 2 0 0 1-2 2h-2"></path><path d="M6 9V3a1 1 0 0 1 1-1h10a1 1 0 0 1 1 1v6"></path><rect x="6" y="14" width="12" height="8" rx="1"></rect></svg>Print Recipe</button></section><section aria-labelledby="tags-header"><h3 id="tags-header">Tags</h3><div><span>#<!-- -->Recipe</span><span>#<!-- -->dinner</span><span>#<!-- -->Lemon</span></div></section></aside></div></main>',
];

